import React, { useState } from 'react';
import { 
  BarChart3, 
  TrendingUp, 
  Users, 
  DollarSign, 
  AlertTriangle,
  Calendar,
  RefreshCw,
  Download,
  Eye,
  BookOpen,
  HelpCircle,
  Filter,
  Shield
} from 'lucide-react';
import { Line } from 'react-chartjs-2';
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend,
} from 'chart.js';

ChartJS.register(
  CategoryScale,
  LinearScale,
  PointElement,
  LineElement,
  Title,
  Tooltip,
  Legend
);

const AccountantDashboard = ({ debugMode }) => {
  const [selectedPeriod, setSelectedPeriod] = useState('6months');
  const [showAIForecast, setShowAIForecast] = useState(false);
  const [managementFilter, setManagementFilter] = useState('all');
  const [showQuickGuide, setShowQuickGuide] = useState(false);

  // Mock data for AI Revenue Forecast
  const revenueData = {
    labels: ['Tháng 8', 'Tháng 9', 'Tháng 10', 'Tháng 11', 'Tháng 12', 'Tháng 1'],
    datasets: [
      {
        label: 'Doanh thu thực tế',
        data: [850000000, 920000000, 780000000, 1100000000, 1250000000, 950000000],
        borderColor: 'rgb(59, 130, 246)',
        backgroundColor: 'rgba(59, 130, 246, 0.1)',
        tension: 0.4,
      },
      {
        label: 'Dự báo AI',
        data: [null, null, null, null, null, 1050000000],
        borderColor: 'rgb(239, 68, 68)',
        backgroundColor: 'rgba(239, 68, 68, 0.1)',
        borderDash: [5, 5],
        tension: 0.4,
      },
    ],
  };

  const chartOptions = {
    responsive: true,
    plugins: {
      legend: {
        position: 'top',
      },
      title: {
        display: true,
        text: 'Dự báo Doanh thu Học phí',
      },
    },
    scales: {
      y: {
        beginAtZero: true,
        ticks: {
          callback: function(value) {
            return new Intl.NumberFormat('vi-VN', {
              style: 'currency',
              currency: 'VND',
              minimumFractionDigits: 0,
              maximumFractionDigits: 0,
            }).format(value);
          },
        },
      },
    },
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('vi-VN', {
      style: 'currency',
      currency: 'VND',
      minimumFractionDigits: 0,
      maximumFractionDigits: 0,
    }).format(amount);
  };

  const summaryStats = [
    {
      title: 'Tổng doanh thu',
      value: 5750000000,
      change: '+12.5%',
      icon: DollarSign,
      color: 'text-green-600',
      bgColor: 'bg-green-50'
    },
    {
      title: 'Số sinh viên đã nộp',
      value: 2847,
      change: '+8.2%',
      icon: Users,
      color: 'text-blue-600',
      bgColor: 'bg-blue-50'
    },
    {
      title: 'Tỷ lệ nợ',
      value: '15.3%',
      change: '-3.1%',
      icon: AlertTriangle,
      color: 'text-yellow-600',
      bgColor: 'bg-yellow-50'
    },
    {
      title: 'Giao dịch hôm nay',
      value: 156,
      change: '+24.7%',
      icon: TrendingUp,
      color: 'text-purple-600',
      bgColor: 'bg-purple-50'
    }
  ];

  const recentTransactions = [
    {
      id: 'TXN001',
      studentId: '2021001234',
      studentName: 'Nguyễn Văn A',
      amount: 5000000,
      method: 'QR Code',
      status: 'Thành công',
      time: '14:30:25'
    },
    {
      id: 'TXN002',
      studentId: '2021005678',
      studentName: 'Trần Thị B',
      amount: 3000000,
      method: 'Chuyển khoản',
      status: 'Thành công',
      time: '14:28:15'
    },
    {
      id: 'TXN003',
      studentId: '2021009012',
      studentName: 'Lê Văn C',
      amount: 8000000,
      method: 'QR Code',
      status: 'Đang xử lý',
      time: '14:25:42'
    }
  ];

  const reconciliationLogs = [
    {
      id: 'WEB001',
      gateway: 'VNPAY',
      transactionCount: 1250,
      totalAmount: 6250000000,
      status: 'Thành công',
      processedAt: '2024-01-15 14:00:00'
    },
    {
      id: 'WEB002',
      gateway: 'MoMo',
      transactionCount: 890,
      totalAmount: 4450000000,
      status: 'Thành công',
      processedAt: '2024-01-15 13:30:00'
    }
  ];

  return (
    <div className="p-6">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-gray-900 mb-2">
          Dashboard Báo cáo
          {debugMode && <span className="ml-2 px-2 py-1 bg-purple-100 text-purple-800 text-xs rounded">[ADMIN]</span>}
        </h1>
        <p className="text-gray-600">Tổng quan hệ thống quản lý tài chính</p>
      </div>

      {/* Summary Stats */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-4 mb-6">
        {summaryStats.map((stat, index) => {
          const Icon = stat.icon;
          return (
            <div key={index} className="card">
              <div className="flex items-center justify-between">
                <div>
                  <p className="text-sm text-gray-600">{stat.title}</p>
                  <p className="text-2xl font-bold text-gray-900">
                    {typeof stat.value === 'number' ? formatCurrency(stat.value) : stat.value}
                  </p>
                  <p className={`text-sm ${stat.color}`}>
                    {stat.change} so với tháng trước
                  </p>
                </div>
                <div className={`w-12 h-12 ${stat.bgColor} rounded-lg flex items-center justify-center`}>
                  <Icon className={`w-6 h-6 ${stat.color}`} />
                </div>
              </div>
            </div>
          );
        })}
      </div>

      {/* AI Revenue Forecast Section */}
      <div className="card mb-6">
        <div className="flex justify-between items-center mb-4">
          <h2 className="text-lg font-semibold text-gray-900">Dự báo Doanh thu AI</h2>
          <select
            value={selectedPeriod}
            onChange={(e) => setSelectedPeriod(e.target.value)}
            className="border border-gray-300 rounded-lg px-3 py-2 text-sm"
          >
            <option value="3months">3 tháng</option>
            <option value="6months">6 tháng</option>
            <option value="1year">1 năm</option>
          </select>
        </div>

        {/* RISK WARNING BANNER - TC11 */}
        <div className="bg-red-50 border-2 border-red-200 rounded-lg p-4 mb-4">
          <div className="flex items-start space-x-3">
            <AlertTriangle className="w-6 h-6 text-red-600 mt-0.5 flex-shrink-0" />
            <div>
              <h4 className="font-bold text-red-800 mb-1">
                CẢNH BÁO RỦI RO AI
              </h4>
              <p className="text-red-700 text-sm leading-relaxed">
                Hệ thống hiện tại chỉ mới thu thập được dữ liệu của 2 tháng. 
                Module AI cần ít nhất dữ liệu của 1 học kỳ (5 tháng) để đưa ra dự báo có độ chính xác cao. 
                Dữ liệu dưới đây chỉ mang tính chất tham khảo.
              </p>
            </div>
          </div>
        </div>

        <div className="h-96">
          <Line data={revenueData} options={chartOptions} />
        </div>

        <div className="mt-4 grid grid-cols-1 md:grid-cols-3 gap-4">
          <div className="bg-blue-50 p-3 rounded-lg">
            <p className="text-sm text-blue-600">Tổng doanh thu thực tế</p>
            <p className="text-lg font-bold text-blue-800">
              {formatCurrency(5750000000)}
            </p>
          </div>
          <div className="bg-red-50 p-3 rounded-lg">
            <p className="text-sm text-red-600">Dự báo tháng tới</p>
            <p className="text-lg font-bold text-red-800">
              {formatCurrency(1050000000)}
            </p>
          </div>
          <div className="bg-green-50 p-3 rounded-lg">
            <p className="text-sm text-green-600">Độ tin cậy</p>
            <p className="text-lg font-bold text-green-800">45%</p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Recent Transactions */}
        <div className="card">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-semibold text-gray-900">Giao dịch gần đây</h2>
            <button className="text-primary-600 hover:text-primary-700">
              <Eye className="w-4 h-4" />
            </button>
          </div>

          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b">
                  <th className="text-left py-2 text-xs font-medium text-gray-700">Mã GD</th>
                  <th className="text-left py-2 text-xs font-medium text-gray-700">Sinh viên</th>
                  <th className="text-left py-2 text-xs font-medium text-gray-700">Số tiền</th>
                  <th className="text-left py-2 text-xs font-medium text-gray-700">Trạng thái</th>
                </tr>
              </thead>
              <tbody>
                {recentTransactions.map((transaction) => (
                  <tr key={transaction.id} className="border-b">
                    <td className="py-2 text-xs">{transaction.id}</td>
                    <td className="py-2 text-xs">
                      <div>
                        <p className="font-medium">{transaction.studentName}</p>
                        <p className="text-gray-500">{transaction.studentId}</p>
                      </div>
                    </td>
                    <td className="py-2 text-xs font-medium">
                      {formatCurrency(transaction.amount)}
                    </td>
                    <td className="py-2 text-xs">
                      <span className={`px-2 py-1 rounded text-xs ${
                        transaction.status === 'Thành công' 
                          ? 'bg-green-100 text-green-800'
                          : 'bg-yellow-100 text-yellow-800'
                      }`}>
                        {transaction.status}
                      </span>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        {/* Reconciliation Logs */}
        <div className="card">
          <div className="flex justify-between items-center mb-4">
            <h2 className="text-lg font-semibold text-gray-900">Đối soát Webhook</h2>
            <button className="text-primary-600 hover:text-primary-700">
              <RefreshCw className="w-4 h-4" />
            </button>
          </div>

          <div className="space-y-3">
            {reconciliationLogs.map((log) => (
              <div key={log.id} className="border rounded-lg p-3">
                <div className="flex justify-between items-start mb-2">
                  <div>
                    <p className="font-medium text-sm">{log.gateway}</p>
                    <p className="text-xs text-gray-500">{log.processedAt}</p>
                  </div>
                  <span className="bg-green-100 text-green-800 px-2 py-1 rounded text-xs">
                    {log.status}
                  </span>
                </div>
                <div className="grid grid-cols-2 gap-2 text-xs">
                  <div>
                    <p className="text-gray-600">Số giao dịch:</p>
                    <p className="font-medium">{log.transactionCount}</p>
                  </div>
                  <div>
                    <p className="text-gray-600">Tổng tiền:</p>
                    <p className="font-medium">{formatCurrency(log.totalAmount)}</p>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Action Buttons */}
      <div className="mt-6 flex justify-center space-x-3">
        <button className="btn-primary flex items-center">
          <Download className="w-4 h-4 mr-2" />
          Tải báo cáo
        </button>
        <button className="btn-secondary flex items-center">
          <Calendar className="w-4 h-4 mr-2" />
          Lên lịch báo cáo
        </button>
      </div>
    </div>
  );
};

export default AccountantDashboard;
